mapper.select:
SELECT S.SEQ, S.RESUME_SEQ, S.SCHEDULE_TYPE, S.NO, S.NAME, S.DEPTNO, S.DEPTNAME, S.POST_GRADE_NO, S.POST_GRADE_NAME, S.EVS_OBJECT, S.EVS_STEP, GET_GLOBAL_NAME(S.EVS_STEP, #{lang, jdbcType=VARCHAR}) AS EVS_STEP_NAME, S.ACTIVITY, S.DEPT_TYPE, TO_CHAR(S.ORDER_NO) AS ORDER_NO, S.PERSON_ID, TO_CHAR(S.START_DATE, 'YYYY-MM-DD') AS START_DATE, TO_CHAR(S.END_DATE, 'YYYY-MM-DD') AS END_DATE, TO_CHAR(S.CREATE_DATE, 'YYYY-MM-DD HH24:MI:SS') AS CREATE_DATE, GET_UPDATED_INFO(S.CREATED_BY) || ' ' || S.CREATED_IP AS CREATED_BY, TO_CHAR(S.UPDATE_DATE, 'YYYY-MM-DD HH24:MI') AS UPDATE_DATE, GET_UPDATED_INFO(S.UPDATED_BY) || ' ' || S.UPDATED_IP AS UPDATED_BY FROM EVS_SCHEDULE S WHERE ACTIVITY != 2
AND S.RESUME_SEQ = #{resumeSeq, jdbcType=VARCHAR}
AND S.SCHEDULE_TYPE = #{scheduleType, jdbcType=VARCHAR}
ORDER BY S.ORDER_NO, S.SEQ

mapper.delete:
UPDATE EVS_SCHEDULE
SET UPDATE_DATE = SYSDATE,
    UPDATED_BY = #{adminID, jdbcType=VARCHAR},
    ACTIVITY = 2,
    UPDATED_IP = #{adminIP, jdbcType=VARCHAR}
WHERE SEQ     = #{seq,    jdbcType=VARCHAR}
